class Solution:
    def maxScoreIndices(self, nums: List[int]) -> List[int]:
        total_ones = sum(nums)
        current_ones = 0
        max_score = -1
        result = []
        n = len(nums)
        for i in range(n + 1):
            score = i + total_ones - 2 * current_ones
            if score > max_score:
                max_score = score
                result = [i]
            elif score == max_score:
                result.append(i)
            if i < n:
                current_ones += nums[i]
        return result

